/**
 * Normalizes text according to TaleVox requirements:
 * - CRLF -> LF
 * - NBSP -> Space
 * - Remove Zero-width chars
 * - Trim lines
 * - Max 2 consecutive newlines
 */
export function cleanText(text: string): string {
    if (!text) return '';

    return text
        // Normalize newlines
        .replace(/\r\n/g, '\n')
        .replace(/\r/g, '\n')
        // Replace non-breaking spaces
        .replace(/\u00A0/g, ' ')
        // Remove zero-width characters (ZWSP, BOM, etc)
        .replace(/[\u200B-\u200D\uFEFF]/g, '')
        // Trim each line
        .split('\n')
        .map(line => line.trim())
        .join('\n')
        // Ensure no more than 2 consecutive newlines (paragraph breaks)
        .replace(/\n{3,}/g, '\n\n')
        .trim();
}

/**
 * Parses the raw title to extract the chapter index and the clean descriptive title.
 * e.g. "Path of Dragons 12 - Chapter 47 - Loops" -> { index: 47, title: "Loops" }
 */
export function parseChapterMetadata(rawTitle: string): { index: number | null, title: string } {
    if (!rawTitle) return { index: null, title: '' };

    // Normalize dashes to standard hyphens for easier regex
    let text = rawTitle.replace(/[\u2013\u2014]/g, '-').trim();
    let index: number | null = null;
    let title = text;

    // 1. Locate the "Chapter X" token
    // Matches "Chapter 47", "Ch. 47", "Episode 12", etc.
    const chapRegex = /(?:chapter|ch\.?|episode|ep\.?)\s*(\d+(?:[\.\-]\d+)?)/i;
    const match = text.match(chapRegex);

    if (match) {
        // Extract Index
        const numStr = match[1];
        // Handle "47-1" as 47.1 for sorting, or just 47
        const parsed = parseFloat(numStr.replace('-', '.'));
        if (!isNaN(parsed)) index = parsed;

        // 2. Extract Title
        // Everything AFTER the match is potentially the title.
        // e.g. "Series - Chapter 47 - Loops" -> match matches "Chapter 47"
        // Post-match string is " - Loops"
        const endOfMatchIndex = match.index! + match[0].length;
        const potentialSuffix = text.substring(endOfMatchIndex);

        // Clean the suffix: remove leading separators like " - ", ": ", " | "
        const cleanSuffix = potentialSuffix.replace(/^[\s:\-\.|]+/, '').trim();

        if (cleanSuffix.length > 0) {
            // We found a title suffix (e.g. "Loops")
            title = cleanSuffix;
        } else {
            // No suffix found. Title is empty (generic chapter).
            // We discard the prefix (Series Name) because usually we just want the chapter info.
            title = '';
        }
    } else {
        // Fallback: No "Chapter" keyword found.
        // Check for simple "47. Loops" or "47 - Loops" pattern often found in pure lists
        const simpleRegex = /^(\d+)(?:[\.\-:\s])+(.+)$/;
        const simpleMatch = text.match(simpleRegex);
        if (simpleMatch) {
            index = parseFloat(simpleMatch[1]);
            title = simpleMatch[2].trim();
        }
    }

    return { index, title };
}

/**
 * Formats the file content:
 * Chapter {index}: {CleanTitle}
 * (blank line)
 * [CHAPTER BODY TEXT]
 */
export function formatChapterContent(index: number | null, title: string, content: string): string {
    const idx = index !== null ? index : 1;
    let header = `Chapter ${idx}`;
    if (title) {
        header += `: ${title}`;
    }

    const body = cleanText(content);
    return `${header}\n\n${body}`;
}

export function buildFilename(seriesSlug: string, index: number, title: string): string {
    const paddedIndex = index.toString().padStart(4, '0');
    let safeTitle = title.toLowerCase().trim();
    safeTitle = safeTitle.replace(/\s+/g, '_');
    safeTitle = safeTitle.replace(/[^a-z0-9_\-]/g, '');
    safeTitle = safeTitle.substring(0, 60);
    safeTitle = safeTitle.replace(/[_\-]+$/, '');

    // If title is empty, just use 'chapter'
    if (!safeTitle) safeTitle = 'chapter';

    return `${seriesSlug}__${paddedIndex}__${safeTitle}.txt`;
}

