import React, { useState } from 'react';
import { Play, Download, Loader2, AlertCircle, Terminal, FileText, Bug } from 'lucide-react';
import { ExtractedChapter, ExtractionResponse } from '../types';
import { fetchJson } from '../src/lib/http';
import { formatChapterContent, parseChapterMetadata } from '../src/lib/talevox';

export default function SingleExtract() {
  const [url, setUrl] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<ExtractedChapter | null>(null);
  const [parsedMeta, setParsedMeta] = useState<{index: number | null, title: string} | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [debugInfo, setDebugInfo] = useState<any>(null);

  const handleExtract = async () => {
    if (!url) return;
    setLoading(true);
    setError(null);
    setResult(null);
    setParsedMeta(null);
    setDebugInfo(null);

    try {
      const resp = await fetchJson<ExtractionResponse>('/api/extract', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ url }),
      });

      if (resp.success && resp.data) {
          setResult(resp.data);
          // Parse metadata immediately for display
          const meta = parseChapterMetadata(resp.data.title);
          setParsedMeta(meta);

          // @ts-ignore
          if (resp.data.debugMetadata) setDebugInfo(resp.data.debugMetadata);
      } else {
          setError(resp.error || 'Unknown error');
      }
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const copy = (text: string) => navigator.clipboard.writeText(text);

  const getFormattedContent = () => {
      if (!result) return '';
      const meta = parseChapterMetadata(result.title);
      return formatChapterContent(meta.index, meta.title, result.content);
  };

  const download = () => {
    if (!result || !parsedMeta) return;

    const formatted = getFormattedContent();
    const isMd = result.hasRichContent;
    const ext = isMd ? 'md' : 'txt';

    const blob = new Blob([formatted], {type: 'text/plain'});
    const a = document.createElement("a");
    a.href = URL.createObjectURL(blob);
    // Use parsed title for filename if available
    const safeTitle = (parsedMeta.title || 'chapter').replace(/[^a-z0-9]/gi, '_');
    a.download = `${safeTitle}.${ext}`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="border-l-4 border-katana pl-4">
        <h2 className="text-3xl font-bold text-white tracking-tight uppercase">Single Extraction</h2>
        <p className="text-steel font-mono text-sm">Target singular web entity for processing.</p>
      </div>

      <div className="bg-armor border border-white/10 p-1 flex">
        <div className="flex-1 bg-plate relative group">
            <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
              <Terminal className="h-4 w-4 text-steel" />
            </div>
            <input
              type="url"
              value={url}
              onChange={(e) => setUrl(e.target.value)}
              placeholder="ENTER TARGET URL..."
              className="w-full bg-transparent text-white p-4 pl-12 focus:outline-none font-mono text-sm"
              onKeyDown={e => e.key === 'Enter' && handleExtract()}
            />
        </div>
        <button
            onClick={handleExtract}
            disabled={loading || !url}
            className="bg-katana hover:bg-red-600 text-black px-8 font-bold uppercase tracking-widest disabled:opacity-50 transition-all flex items-center gap-2"
        >
            {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : <Play className="w-5 h-5 fill-current" />}
            Execute
        </button>
      </div>

      {error && (
        <div className="bg-red-950/30 text-red-400 p-4 border border-red-900/50 flex items-center gap-3 font-mono text-sm">
          <AlertCircle className="w-5 h-5 shrink-0" />
          <p>&gt; ERR: {error}</p>
        </div>
      )}

      {result && parsedMeta && (
        <div className="bg-armor border border-white/10 relative flex flex-col h-[600px]">
          <div className="bg-black/40 px-6 py-4 border-b border-white/5 flex justify-between items-center backdrop-blur-sm">
            <div>
              <h3 className="font-bold text-white text-lg tracking-wide">
                {parsedMeta.index !== null ? `Chapter ${parsedMeta.index}: ${parsedMeta.title}` : parsedMeta.title || result.title}
              </h3>
              <div className="flex items-center gap-2 mt-1">
                  <span className="text-[10px] bg-katana text-black px-2 py-0.5 font-bold uppercase">TaleVox Format</span>
                  <p className="text-[10px] text-steel font-mono uppercase tracking-wider truncate max-w-md">
                      ORIGINAL: {result.title}
                  </p>
              </div>
            </div>
            <div className="flex gap-2">
              <button onClick={() => copy(getFormattedContent())} className="px-3 py-1 bg-white/5 hover:bg-white/10 text-xs font-mono uppercase border border-white/10">Copy All</button>
              <button onClick={download} className="px-3 py-1 bg-katana hover:bg-red-600 text-black text-xs font-mono uppercase font-bold flex items-center gap-2">
                  <Download className="w-3 h-3"/> Download
              </button>
            </div>
          </div>

          <div className="flex-1 flex min-h-0">
              {/* Content Preview */}
              <div className="flex-1 overflow-y-auto p-8 custom-scrollbar border-r border-white/5">
                <pre className="whitespace-pre-wrap font-serif text-lg leading-relaxed text-gray-300 font-light max-w-3xl mx-auto">
                  {getFormattedContent()}
                </pre>
              </div>

              {/* Debug Panel */}
              {debugInfo && (
                  <div className="w-64 bg-black/20 p-4 overflow-y-auto custom-scrollbar font-mono text-[10px] space-y-4">
                      <div className="flex items-center gap-2 text-katana font-bold uppercase border-b border-white/10 pb-2">
                          <Bug className="w-3 h-3" /> Extraction Debug
                      </div>

                      <div>
                          <span className="text-steel block mb-1">USED SELECTOR</span>
                          <code className="text-white break-all bg-white/5 p-1 block">{debugInfo.usedSelector}</code>
                      </div>

                      <div>
                          <span className="text-steel block mb-1">TITLE SOURCE</span>
                          <code className="text-white break-all bg-white/5 p-1 block">{debugInfo.titleSelector}</code>
                      </div>

                      {debugInfo.removedElements && debugInfo.removedElements.length > 0 && (
                          <div>
                              <span className="text-steel block mb-1">REMOVED ELEMENTS</span>
                              <div className="space-y-1">
                                  {debugInfo.removedElements.map((el: string, i: number) => (
                                      <div key={i} className="text-red-400 truncate border-l border-red-900 pl-1">{el}</div>
                                  ))}
                              </div>
                          </div>
                      )}
                  </div>
              )}
          </div>
        </div>
      )}
    </div>
  );
}

/**
 * Normalizes text according to TaleVox requirements:
 * - CRLF -> LF
 * - NBSP -> Space
 * - Remove Zero-width chars
 * - Trim lines
 * - Max 2 consecutive newlines
 */
export function cleanText(text: string): string {
    if (!text) return '';

    return text
        // Normalize newlines
        .replace(/\r\n/g, '\n')
        .replace(/\r/g, '\n')
        // Replace non-breaking spaces
        .replace(/\u00A0/g, ' ')
        // Remove zero-width characters (ZWSP, BOM, etc)
        .replace(/[\u200B-\u200D\uFEFF]/g, '')
        // Trim each line
        .split('\n')
        .map(line => line.trim())
        .join('\n')
        // Ensure no more than 2 consecutive newlines (paragraph breaks)
        .replace(/\n{3,}/g, '\n\n')
        .trim();
}

/**
 * Parses the raw title to extract the chapter index and the clean descriptive title.
 * e.g. "Path of Dragons 12 - Chapter 47 - Loops" -> { index: 47, title: "Loops" }
 */
export function parseChapterMetadata(rawTitle: string): { index: number | null, title: string } {
    if (!rawTitle) return { index: null, title: '' };

    // Normalize dashes/separators
    let text = rawTitle.replace(/[\u2010-\u2015\u2212]/g, '-').trim();
    let index: number | null = null;
    let title = text;

    // Strategy 1: Explicit "Chapter X" pattern (Priority)
    // Matches: "Chapter 47", "Ch.47", "Episode 12" anywhere in the string
    const chapRegex = /(?:chapter|ch\.?|episode|ep\.?)\s*(\d+(?:[\.\-]\d+)?)/i;
    const match = text.match(chapRegex);

    if (match) {
        const numStr = match[1];
        const parsed = parseFloat(numStr.replace('-', '.'));
        if (!isNaN(parsed)) {
            index = parsed;

            // Extract title part: Everything AFTER the match
            const endIdx = (match.index || 0) + match[0].length;
            const suffix = text.substring(endIdx);

            // Clean leading separators from suffix
            const cleanSuffix = suffix.replace(/^[\s:\-\.\|,]+/, '').trim();

            if (cleanSuffix) {
                // If suffix exists, that's our title (e.g. "Loops")
                title = cleanSuffix;
            } else {
                // If suffix is empty (e.g. "Series - Chapter 47"), 
                // we assume the prefix is the series name and we have no chapter title.
                title = '';
            }
        }
    }

    // Strategy 2: Fallback for "Series - 47 - Title" (Number surrounded by hyphens)
    // Useful if "Chapter" word is missing
    if (index === null) {
         const midNumRegex = /[\-–—\|]\s*(\d+(?:[\.]\d+)?)\s*[\-–—\|]\s*(.+)$/;
         const midMatch = text.match(midNumRegex);
         if (midMatch) {
             const parsed = parseFloat(midMatch[1]);
             if (!isNaN(parsed)) {
                index = parsed;
                title = midMatch[2].trim();
             }
         }
    }

    // Strategy 3: Fallback for "47 - Title" (Start of string)
    if (index === null) {
        const startRegex = /^(\d+(?:[\.]\d+)?)(?:\s*[\-–—:\.]\s*|\s+)(.+)$/;
        const startMatch = text.match(startRegex);
        if (startMatch) {
             const parsed = parseFloat(startMatch[1]);
             if (!isNaN(parsed)) {
                index = parsed;
                title = startMatch[2].trim();
             }
        }
    }

    return { index, title };
}

/**
 * Formats the file content.
 * Does NOT default to "Chapter 1" if index is missing to avoid confusion.
 */
export function formatChapterContent(index: number | null, title: string, content: string): string {
    const body = cleanText(content);

    if (index !== null) {
        // We found an index (e.g. 47)
        let header = `Chapter ${index}`;
        if (title) header += `: ${title}`;
        return `${header}\n\n${body}`;
    }

    // Fallback: No index found. Use the title if available, otherwise generic.
    // e.g. "Prologue" or "Path of Dragons 12 - Chapter 47 - Loops" (if regex failed completely)
    const header = title || 'Chapter';
    return `${header}\n\n${body}`;
}

export function buildFilename(seriesSlug: string, index: number, title: string): string {
    const paddedIndex = index.toString().padStart(4, '0');
    let safeTitle = title.toLowerCase().trim();
    safeTitle = safeTitle.replace(/\s+/g, '_');
    safeTitle = safeTitle.replace(/[^a-z0-9_\-]/g, '');
    safeTitle = safeTitle.substring(0, 60);
    safeTitle = safeTitle.replace(/[_\-]+$/, '');

    // If title is empty, just use 'chapter'
    if (!safeTitle) safeTitle = 'chapter';

    return `${seriesSlug}__${paddedIndex}__${safeTitle}.txt`;
}

