async function ensureDir(dir: string) {
  try {
    await fsp.mkdir(dir, { recursive: true });
  } catch (e) {
    // ignore if exists
  }
}

async function readJson<T>(file: string, defaultVal: T): Promise<T> {
  try {
    const data = await fsp.readFile(file, 'utf-8');
    if (!data.trim()) return defaultVal;
    return JSON.parse(data);
  } catch (e) {
    return defaultVal;
  }
}

async function writeJson(file: string, data: any) {
  await ensureDir(path.dirname(file));
  await fsp.writeFile(file, JSON.stringify(data, null, 2), 'utf-8');
}

export async function seedDefaults() {
  const currentTemplates = await getTemplates();
  let changed = false;

  for (const def of DEFAULT_TEMPLATES) {
      const idx = currentTemplates.findIndex(t => t.id === def.id);

      if (idx === -1) {
          currentTemplates.push(def);
          changed = true;
      } else {
          const existing = currentTemplates[idx];
          if (existing.contentSelector !== def.contentSelector || existing.titleSelector !== def.titleSelector) {
             console.log(`[Storage] Updating default protocol definition for: ${def.domain}`);
             currentTemplates[idx] = {
                 ...existing,
                 titleSelector: def.titleSelector,
                 contentSelector: def.contentSelector,
                 removeSelectors: def.removeSelectors,
                 updatedAt: Date.now()
             };
             changed = true;
          }
      }
  }

  if (changed) {
      await saveTemplates(currentTemplates);
      console.log('Seeded/Updated default protocols.');
      return true;
  }
  return false;
}

export async function initStorage() {
  await ensureDir(DATA_DIR);
  await seedDefaults();
}

export async function getSettings(): Promise<AppSettings> {
  const loaded = await readJson<Partial<AppSettings>>(SETTINGS_FILE, {});
  return { ...DEFAULT_SETTINGS, ...loaded };
}

export async function saveSettings(settings: AppSettings) {
  await writeJson(SETTINGS_FILE, settings);
}

export async function getTemplates(): Promise<ProtocolTemplate[]> {
  return readJson<ProtocolTemplate[]>(TEMPLATES_FILE, []);
}

export async function saveTemplates(templates: ProtocolTemplate[]) {
  await writeJson(TEMPLATES_FILE, templates);
}

/**
 * Normalizes text according to TaleVox requirements:
 * - CRLF -> LF
 * - NBSP -> Space
 * - Remove Zero-width chars
 * - Trim lines
 * - Max 2 consecutive newlines
 */
export function cleanText(text: string): string {
    if (!text) return '';

    return text
        // Normalize newlines
        .replace(/\r\n/g, '\n')
        .replace(/\r/g, '\n')
        // Replace non-breaking spaces
        .replace(/\u00A0/g, ' ')
        // Remove zero-width characters (ZWSP, BOM, etc)
        .replace(/[\u200B-\u200D\uFEFF]/g, '')
        // Trim each line
        .split('\n')
        .map(line => line.trim())
        .join('\n')
        // Ensure no more than 2 consecutive newlines (paragraph breaks)
        .replace(/\n{3,}/g, '\n\n')
        .trim();
}

/**
 * Parses the raw title to extract the chapter index and the clean descriptive title.
 * e.g. "Path of Dragons 12 - Chapter 47 - Loops" -> { index: 47, title: "Loops" }
 * e.g. "Chapter 995: An Odd Pairing" -> { index: 995, title: "An Odd Pairing" }
 */
export function parseChapterMetadata(rawTitle: string): { index: number | null, title: string } {
    if (!rawTitle) return { index: null, title: '' };

    // 1. Normalize text and dashes
    let text = rawTitle.replace(/[\u2010-\u2015\u2212]/g, '-').trim();

    let index: number | null = null;
    let title = '';

    // 2. Primary Strategy: Find "Chapter X" marker
    // Captures: 
    // Group 1: The Number (e.g. "47", "47-1", "47.5")
    // Group 2: The Suffix (everything after the number)
    const chapRegex = /(?:chapter|ch\.?|episode|ep\.?)\s*(\d+(?:[\.\-]\d+)?)(.*)$/i;
    const match = text.match(chapRegex);

    if (match) {
        // Parse Index
        const numStr = match[1];
        // Handle hyphenated numbers like 47-1 -> 47.1
        const parsedIdx = parseFloat(numStr.replace('-', '.'));
        if (!isNaN(parsedIdx)) index = parsedIdx;

        // Parse Title from Suffix
        const suffix = match[2];
        if (suffix) {
             // Remove leading separators: " - ", ": ", ". ", " | "
             title = suffix.replace(/^[\s:\-\.\|,]+/, '').trim();
        }
    } 
    // 3. Fallback Strategy: Look for "Number - Title" pattern if no "Chapter" word exists
    else {
        // Matches "47 - Loops" or "47. Loops"
        const simpleRegex = /^(\d+(?:[\.]\d+)?)\s*[\-–—:\.]\s*(.+)$/;
        const simpleMatch = text.match(simpleRegex);
        if (simpleMatch) {
            const parsedIdx = parseFloat(simpleMatch[1]);
            if (!isNaN(parsedIdx)) {
                index = parsedIdx;
                title = simpleMatch[2].trim();
            }
        }
    }

    // Final cleanup: If title is strictly numeric or same as index (e.g. "Chapter 47: 47"), clear it
    if (title && /^\d+$/.test(title) && parseFloat(title) === index) {
        title = '';
    }

    // If we failed to parse anything but the string is short, it might be a Prologue or Epilogue
    if (index === null && text.length < 50) {
        title = text;
    }

    return { index, title };
}

/**
 * Formats the file content.
 * Chapter {index}: {CleanTitle} (if title exists)
 * Chapter {index} (if title is empty)
 */
export function formatChapterContent(index: number | null, title: string, content: string): string {
    const body = cleanText(content);
    let header = '';

    if (index !== null) {
        header = `Chapter ${index}`;
        if (title) {
            header += `: ${title}`;
        }
    } else {
        // If no index, use title as header, or fallback to 'Chapter'
        header = title || 'Chapter';
    }

    return `${header}\n\n${body}`;
}

export function buildFilename(seriesSlug: string, index: number, title: string): string {
    const paddedIndex = index.toString().padStart(4, '0');

    let safeTitle = (title || 'chapter').toLowerCase().trim();
    safeTitle = safeTitle.replace(/\s+/g, '_');
    safeTitle = safeTitle.replace(/[^a-z0-9_\-]/g, '');
    safeTitle = safeTitle.substring(0, 60);
    safeTitle = safeTitle.replace(/[_\-]+$/, '');

    // Fallback if sanitization kills everything
    if (!safeTitle) safeTitle = 'chapter';

    return `${seriesSlug}__${paddedIndex}__${safeTitle}.txt`;
}

import React, { useState } from 'react';
import { Play, Download, Loader2, AlertCircle, Terminal, FileText, Bug } from 'lucide-react';
import { ExtractedChapter, ExtractionResponse } from '../types';
import { fetchJson } from '../src/lib/http';
import { formatChapterContent, parseChapterMetadata } from '../src/lib/talevox';

export default function SingleExtract() {
  const [url, setUrl] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<ExtractedChapter | null>(null);
  const [parsedMeta, setParsedMeta] = useState<{index: number | null, title: string} | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [debugInfo, setDebugInfo] = useState<any>(null);

  const handleExtract = async () => {
    if (!url) return;
    setLoading(true);
    setError(null);
    setResult(null);
    setParsedMeta(null);
    setDebugInfo(null);

    try {
      const resp = await fetchJson<ExtractionResponse>('/api/extract', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ url }),
      });

      if (resp.success && resp.data) {
          setResult(resp.data);
          // Parse metadata immediately for display
          const meta = parseChapterMetadata(resp.data.title);
          setParsedMeta(meta);

          // @ts-ignore
          if (resp.data.debugMetadata) setDebugInfo(resp.data.debugMetadata);
      } else {
          setError(resp.error || 'Unknown error');
      }
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const copy = (text: string) => navigator.clipboard.writeText(text);

  const getFormattedContent = () => {
      if (!result) return '';
      const meta = parseChapterMetadata(result.title);
      return formatChapterContent(meta.index, meta.title, result.content);
  };

  const getDisplayHeader = () => {
      if (!parsedMeta) return '';
      if (parsedMeta.index !== null) {
          return parsedMeta.title 
            ? `Chapter ${parsedMeta.index}: ${parsedMeta.title}`
            : `Chapter ${parsedMeta.index}`;
      }
      return parsedMeta.title || result?.title || 'Unknown Chapter';
  };

  const download = () => {
    if (!result || !parsedMeta) return;

    const formatted = getFormattedContent();
    const isMd = result.hasRichContent;
    const ext = isMd ? 'md' : 'txt';

    const blob = new Blob([formatted], {type: 'text/plain'});
    const a = document.createElement("a");
    a.href = URL.createObjectURL(blob);
    // Use parsed title for filename if available
    const safeTitle = (parsedMeta.title || 'chapter').replace(/[^a-z0-9]/gi, '_');
    a.download = `${safeTitle}.${ext}`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="border-l-4 border-katana pl-4">
        <h2 className="text-3xl font-bold text-white tracking-tight uppercase">Single Extraction</h2>
        <p className="text-steel font-mono text-sm">Target singular web entity for processing.</p>
      </div>

      <div className="bg-armor border border-white/10 p-1 flex">
        <div className="flex-1 bg-plate relative group">
            <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
              <Terminal className="h-4 w-4 text-steel" />
            </div>
            <input
              type="url"
              value={url}
              onChange={(e) => setUrl(e.target.value)}
              placeholder="ENTER TARGET URL..."
              className="w-full bg-transparent text-white p-4 pl-12 focus:outline-none font-mono text-sm"
              onKeyDown={e => e.key === 'Enter' && handleExtract()}
            />
        </div>
        <button
            onClick={handleExtract}
            disabled={loading || !url}
            className="bg-katana hover:bg-red-600 text-black px-8 font-bold uppercase tracking-widest disabled:opacity-50 transition-all flex items-center gap-2"
        >
            {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : <Play className="w-5 h-5 fill-current" />}
            Execute
        </button>
      </div>

      {error && (
        <div className="bg-red-950/30 text-red-400 p-4 border border-red-900/50 flex items-center gap-3 font-mono text-sm">
          <AlertCircle className="w-5 h-5 shrink-0" />
          <p>&gt; ERR: {error}</p>
        </div>
      )}

      {result && parsedMeta && (
        <div className="bg-armor border border-white/10 relative flex flex-col h-[600px]">
          <div className="bg-black/40 px-6 py-4 border-b border-white/5 flex justify-between items-center backdrop-blur-sm">
            <div>
              <h3 className="font-bold text-white text-lg tracking-wide">
                {getDisplayHeader()}
              </h3>
              <div className="flex items-center gap-2 mt-1">
                  <span className="text-[10px] bg-katana text-black px-2 py-0.5 font-bold uppercase">TaleVox Format</span>
                  <p className="text-[10px] text-steel font-mono uppercase tracking-wider truncate max-w-md">
                      ORIGINAL: {result.title}
                  </p>
              </div>
            </div>
            <div className="flex gap-2">
              <button onClick={() => copy(getFormattedContent())} className="px-3 py-1 bg-white/5 hover:bg-white/10 text-xs font-mono uppercase border border-white/10">Copy All</button>
              <button onClick={download} className="px-3 py-1 bg-katana hover:bg-red-600 text-black text-xs font-mono uppercase font-bold flex items-center gap-2">
                  <Download className="w-3 h-3"/> Download
              </button>
            </div>
          </div>

          <div className="flex-1 flex min-h-0">
              {/* Content Preview */}
              <div className="flex-1 overflow-y-auto p-8 custom-scrollbar border-r border-white/5">
                <pre className="whitespace-pre-wrap font-serif text-lg leading-relaxed text-gray-300 font-light max-w-3xl mx-auto">
                  {getFormattedContent()}
                </pre>
              </div>

              {/* Debug Panel */}
              {debugInfo && (
                  <div className="w-64 bg-black/20 p-4 overflow-y-auto custom-scrollbar font-mono text-[10px] space-y-4">
                      <div className="flex items-center gap-2 text-katana font-bold uppercase border-b border-white/10 pb-2">
                          <Bug className="w-3 h-3" /> Extraction Debug
                      </div>

                      <div>
                          <span className="text-steel block mb-1">USED SELECTOR</span>
                          <code className="text-white break-all bg-white/5 p-1 block">{debugInfo.usedSelector}</code>
                      </div>

                      <div>
                          <span className="text-steel block mb-1">TITLE SOURCE</span>
                          <code className="text-white break-all bg-white/5 p-1 block">{debugInfo.titleSelector}</code>
                      </div>

                      {debugInfo.removedElements && debugInfo.removedElements.length > 0 && (
                          <div>
                              <span className="text-steel block mb-1">REMOVED ELEMENTS</span>
                              <div className="space-y-1">
                                  {debugInfo.removedElements.map((el: string, i: number) => (
                                      <div key={i} className="text-red-400 truncate border-l border-red-900 pl-1">{el}</div>
                                  ))}
                              </div>
                          </div>
                      )}
                  </div>
              )}
          </div>
        </div>
      )}
    </div>
  );
}

/**
 * Normalizes text according to TaleVox requirements:
 * - CRLF -> LF
 * - NBSP -> Space
 * - Remove Zero-width chars
 * - Trim lines
 * - Max 2 consecutive newlines
 */
export function cleanText(text: string): string {
    if (!text) return '';

    return text
        // Normalize newlines
        .replace(/\r\n/g, '\n')
        .replace(/\r/g, '\n')
        // Replace non-breaking spaces
        .replace(/\u00A0/g, ' ')
        // Remove zero-width characters (ZWSP, BOM, etc)
        .replace(/[\u200B-\u200D\uFEFF]/g, '')
        // Trim each line
        .split('\n')
        .map(line => line.trim())
        .join('\n')
        // Ensure no more than 2 consecutive newlines (paragraph breaks)
        .replace(/\n{3,}/g, '\n\n')
        .trim();
}

/**
 * Parses the raw title to extract the chapter index and the clean descriptive title.
 * e.g. "Path of Dragons 12 - Chapter 47 - Loops" -> { index: 47, title: "Loops" }
 * e.g. "Chapter 995: An Odd Pairing" -> { index: 995, title: "An Odd Pairing" }
 * e.g. "An Odd Pairing - Chapter 995" -> { index: 995, title: "An Odd Pairing" }
 */
export function parseChapterMetadata(rawTitle: string): { index: number | null, title: string } {
    if (!rawTitle) return { index: null, title: '' };

    // 1. Normalize text and dashes
    const text = rawTitle.replace(/[\u2010-\u2015\u2212]/g, '-').trim();

    let index: number | null = null;
    let title = '';

    // Regex to find "Chapter X" or "Episode X"
    // We use a simplified regex to find the marker, then split the string around it
    const markerRegex = /(?:chapter|ch\.?|episode|ep\.?)\s*(\d+(?:[\.\-]\d+)?)/i;
    const match = text.match(markerRegex);

    if (match) {
        const numStr = match[1];
        const parsedIdx = parseFloat(numStr.replace('-', '.'));
        if (!isNaN(parsedIdx)) {
            index = parsedIdx;

            // Determine Title from surrounding text
            // The match is at match.index with length match[0].length
            const startIdx = match.index!;
            const endIdx = startIdx + match[0].length;

            const prefix = text.substring(0, startIdx).trim();
            const suffix = text.substring(endIdx).trim();

            // Strategy: Suffix is preferred (standard format), then Prefix (weird format)

            // 1. Check Suffix
            const cleanSuffix = suffix.replace(/^[\s:\-\.\|,]+/, '').trim();
            if (cleanSuffix) {
                title = cleanSuffix;
            } 
            // 2. Check Prefix if suffix is empty
            else if (prefix) {
                // Remove trailing separators from prefix
                const cleanPrefix = prefix.replace(/[\s:\-\.\|,]+$/, '').trim();
                // Avoid using series name if it's too long or generic? 
                // But generally if format is "Title - Chapter X", Title is the chapter title (or series title).
                // Hard to distinguish Series Name vs Chapter Name here without context.
                // We'll accept it for now.
                if (cleanPrefix) {
                    title = cleanPrefix;
                }
            }
        }
    } 
    // Fallback: Number at start "995 - Title" or "995. Title"
    else {
        const simpleRegex = /^(\d+(?:[\.]\d+)?)\s*[\-–—:\.]\s*(.+)$/;
        const simpleMatch = text.match(simpleRegex);
        if (simpleMatch) {
            const parsedIdx = parseFloat(simpleMatch[1]);
            if (!isNaN(parsedIdx)) {
                index = parsedIdx;
                title = simpleMatch[2].trim();
            }
        }
    }

    // Final Sanity Check
    // If title is just the index repeated (e.g. "47"), clear it
    if (title && /^\d+$/.test(title) && parseFloat(title) === index) {
        title = '';
    }

    // If title looks like "Read Chapter 995...", clean it
    title = title.replace(/^read\s+/i, '');

    // Fallback: If we failed to parse index, but text is short, assume text is the title (Prologue, etc)
    if (index === null && text.length < 100) {
        title = text;
    }

    return { index, title };
}

/**
 * Formats the file content.
 * Chapter {index}: {CleanTitle} (if title exists)
 * Chapter {index} (if title is empty and index exists)
 * {Title} (if index is null)
 */
export function formatChapterContent(index: number | null, title: string, content: string): string {
    const body = cleanText(content);
    let header = '';

    if (index !== null) {
        header = `Chapter ${index}`;
        if (title) {
            header += `: ${title}`;
        }
    } else {
        // No index found. Use title.
        header = title || 'Chapter';
    }

    return `${header}\n\n${body}`;
}

export function buildFilename(seriesSlug: string, index: number, title: string): string {
    const paddedIndex = index.toString().padStart(4, '0');

    let safeTitle = (title || 'chapter').toLowerCase().trim();
    safeTitle = safeTitle.replace(/\s+/g, '_');
    safeTitle = safeTitle.replace(/[^a-z0-9_\-]/g, '');
    safeTitle = safeTitle.substring(0, 60);
    safeTitle = safeTitle.replace(/[_\-]+$/, '');

    if (!safeTitle) safeTitle = 'chapter';

    return `${seriesSlug}__${paddedIndex}__${safeTitle}.txt`;
}

