  const handleExtract = async () => {
    if (!url) return;
    setLoading(true);
    setError(null);
    setResult(null);
    setParsedMeta(null);
    setDebugInfo(null);
    setShowAnalysis(false);
    setAnalysisResult(null);

    try {
      const resp = await fetchJson<ExtractionResponse>('/api/extract', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ url }),
